  const key = 'abcd-1234';
  const payload = { customerId: 'c1', items: [{sku:'A', qty:1}] };
  const r1 = await fetch('/orders', { method:'POST', headers:{'Idempotency-Key': key}, body: JSON.stringify(payload) });
  const r2 = await fetch('/orders', { method:'POST', headers:{'Idempotency-Key': key}, body: JSON.stringify(payload) });
