// Example: E2E test framework setup
describe('Multi-tenant Event Publishing API', () => {
  test('idempotent request handling', async () => {
    const response = await POST('/events', {
      tenant_id: 'tenant-123',
      event_type: 'user.created',
      payload: { user_id: 'user-456' },
      idempotency_key: 'unique-key-123'
