## Code Example
```javascript
// Test skeleton using fetch
const submitBatch = async (events) => {
  const response = await fetch('/events', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ events })
  });
  return { status: response.status, jobId: response.json().jobId };
};

const pollStatus = async (jobId) => {
  let status;
  do {
    const res = await fetch(`/events/${jobId}/status`);
    status = await res.json();
    await new Promise(r => setTimeout(r, 1000));
  } while (status.state === 'processing');
  return status;
};

// Test: idempotency
const result1 = await submitBatch([{ eventId: 'e1', type: 'click', payload: {} }]);
const result2 = await submitBatch([{ eventId: 'e1', type: 'click', payload: {} }]);
assert(result1.jobId !== result2.jobId);
const finalStatus = await pollStatus(result2.jobId);
assert(finalStatus.eventsProcessed === 1);
```

