// Test harness for exactly-once verification
async function testExactlyOnce() {
  const idempotencyKey = uuidv4();
  const payload = generateTelemetryBatch(1024 * 512); // 512KB

  // Send same request multiple times (simulating retries)
  const results = await Promise.all([
    postTelemetry(payload, idempotencyKey),
    postTelemetry(payload, idempotencyKey),
    postTelemetry(payload, idempotencyKey)
  ]);

  // Verify: only ONE record in downstream store
  const downstreamCount = await countRecords(idempotencyKey);
  expect(downstreamCount).toBe(1);
}

// Test ordering under concurrent load
async function testOrdering() {
  const sequences = Array.from({length: 1000}, (_, i) => i);
  await Promise.all(sequences.map(seq => 
    postTelemetry({seq, data: `batch-${seq}`}, `key-${seq}`)
  ));

  const stored = await getAllRecords();
  const isOrdered = stored.every((r, i) => r.seq === i);
  expect(isOrdered).toBe(true);
}
```

