- Message deduplication via unique messageIds for at-least-once delivery
- Reconnection logic with exponential backoff and replay semantics
- Fault injection for broker failover and regional outages
- Latency and throughput SLA validation

## Code Example
```javascript
const WebSocket = require('ws');
const { Kafka } = require('kafkajs');
const Redis = require('ioredis');

const TENANTS = ['tenant-a', 'tenant-b', 'tenant-c'];
const SLA_P95_LATENCY_MS = 400;
const MAX_RECONNECT_ATTEMPTS = 10;
const BASE_BACKOFF_MS = 100;

class MultiTenantTest {
  constructor() {
    this.redis = new Redis();
    this.connections = new Map();
    this.messageIds = new Map();
    this.latencies = [];
  }

  async setup() {
    await this.redis.flushdb();
    for (const tenant of TENANTS) {
      await this.redis.set(`seed:${tenant}`, Math.random().toString(36));
    }
  }

  async connectTenant(tenant) {
    const ws = new WebSocket('wss://api.example.com/feed');
    const clientId = `${tenant}-${Date.now()}`;

    ws.on('open', () => {
      ws.send(JSON.stringify({ type: 'subscribe', tenant, clientId }));
    });

    ws.on('message', (data) => {
      const msg = JSON.parse(data);
      if (msg.tenant !== tenant) {
        throw new Error(`CROSS-TENANT LEAK: ${tenant} received ${msg.tenant} data`);
      }
      const latency = Date.now() - msg.timestamp;
      this.latencies.push(latency);
      this.trackMessageId(msg.messageId, tenant);
    });

    this.connections.set(tenant, ws);
    return ws;
  }

  trackMessageId(messageId, tenant) {
    if (this.messageIds.has(messageId)) {
      const existing = this.messageIds.get(messageId);
      console.log(`DUPLICATE: ${messageId} from ${existing} to ${tenant}`);
    }
    this.messageIds.set(messageId, tenant);
  }

  async simulateBackpressure(tenant) {
    const ws = this.connections.get(tenant);
    ws.send(JSON.stringify({ type: 'pause' }));
  }

  async resumeFeed(tenant) {
    const ws = this.connections.get(tenant);
    ws.send(JSON.stringify({ type: 'resume' }));
  }

  async simulateBrokerOutage(region) {
    console.log(`Simulating broker outage in ${region}`);
  }

  calculatePercentile(arr, p) {
    const sorted = arr.slice().sort((a, b) => a - b);
    const idx = Math.ceil((p / 100) * sorted.length) - 1;
    return sorted[Math.max(0, idx)];
  }

  async validateSLA() {
    const p95 = this.calculatePercentile(this.latencies, 95);
    console.log(`P95 Latency: ${p95}ms`);
    if (p95 > SLA_P95_LATENCY_MS) {
      throw new Error(`SLA VIOLATION: p95 ${p95}ms exceeds ${SLA_P95_LATENCY_MS}ms`);
    }
  }
}
```

This test framework validates all key requirements: per-tenant isolation, at-least-once delivery through messageId deduplication, backpressure handling, and latency SLAs under simulated failure conditions.

