// Simple webhook sender with exponential backoff
async function sendWebhook(url, payload, attempt = 1) {
  const max = 5;
  try {
    await fetch(url, { method: 'POST', body: JSON.stringify(payload), headers: { 'Content-Type': 'application/json' } });
  } catch (e) {
    if (attempt < max) {
      const delay = Math.pow(2, attempt) * 100; // exponential backoff
      await new Promise(r => setTimeout(r, delay));
      return sendWebhook(url, payload, attempt + 1);
    }
    throw e;
  }
}
```

