import { NodeSDK } from '@opentelemetry/sdk-node';
import { JaegerExporter } from '@opentelemetry/exporter-jaeger';
import { BatchSpanProcessor } from '@opentelemetry/sdk-trace-base';
import { trace, SpanStatusCode } from '@opentelemetry/api';

describe('Multi-Tenant API Gateway Tracing', () => {
  let sdk: NodeSDK;
  let testTracer: any;

  beforeAll(async () => {
    sdk = new NodeSDK({
      serviceName: 'e2e-tracing-test',
      spanProcessor: new BatchSpanProcessor(new JaegerExporter()),
    });
    await sdk.start();
    testTracer = trace.getTracer('e2e-test');
  });

  afterAll(async () => await sdk.shutdown());

  describe('Trace Context Propagation', () => {
    it('propagates traceparent across Auth, Gateway, and Tenant Services', async () => {
      const span = testTracer.startSpan('test-request');
      const context = span.spanContext();
      const traceparent = `00-${context.traceId}-${context.spanId}-01`;

      // Simulate request flow
      const authResponse = await callAuthService({ traceparent });
      expect(authResponse.headers['traceparent']).toBe(traceparent);

      const gatewayResponse = await callGateway(authResponse.token, { traceparent });
      expect(gatewayResponse.headers['traceparent']).toMatch(new RegExp(`^00-${context.traceId}`));

      const tenantResponse = await callTenantService(gatewayResponse.token, { traceparent });
      expect(tenantResponse.span.traceId).toBe(context.traceId);
    });

    it('propagates baggage across services', async () => {
      const baggage = testTracer.startActiveSpan('test-baggage', (span) => {
        span.setAttribute('tenant.id', 'tenant-123');
        span.setAttribute('user.id', 'user-456');
        return span;
      });
      // Verify baggage propagates through all services
    });
  });

  describe('Sampling Configuration', () => {
    it('respects configured sampling rate', async () => {
      const sampledTraces = [];
      for (let i = 0; i < 100; i++) {
        const response = await makeRequest({ sampleRate: 0.1 });
        sampledTraces.push(response.traceSampled);
      }
      const sampledCount = sampledTraces.filter(Boolean).length;
      expect(sampledCount).toBeGreaterThan(5);
      expect(sampledCount).toBeLessThan(25);
    });

    it('generates complete spans with required attributes', async () => {
      const span = testTracer.startSpan('test-span');
      span.setAttribute('http.method', 'GET');
      span.setAttribute('http.url', '/api/tenant/users');
      span.setAttribute('tenant.id', 'tenant-123');
      span.end();

      const exportedSpan = await getExportedSpan();
      expect(exportedSpan.attributes['http.method']).toBe('GET');
      expect(exportedSpan.attributes['tenant.id']).toBe('tenant-123');
    });
  });

  describe('Retry and Error Handling', () => {
    it('maintains trace continuity across retries', async () => {
      const span = testTracer.startSpan('retry-test');
      const context = span.spanContext();

      let attempts = 0;
      const response = await callServiceWithRetry({
        onAttempt: () => attempts++,
        traceId: context.traceId,
      });

      expect(attempts).toBe(3);
      const spans = await getAllSpansForTrace(context.traceId);
      expect(spans.length).toBe(3); // Parent + 3 retry spans
    });

    it('captures error spans correctly', async () => {
      const span = testTracer.startSpan('error-test');
      try {
        await failingServiceCall();
      } catch (err) {
        span.setStatus({ code: SpanStatusCode.ERROR, message: err.message });
        span.recordException(err);
      } finally {
        span.end();
      }

      const exportedSpan = await getExportedSpan();
      expect(exportedSpan.status.code).toBe(SpanStatusCode.ERROR);
      expect(exportedSpan.events).toContain(expect.objectContaining({ name: 'exception' }));
    });
  });

  describe('Observability Correlation', () => {
    it('correlates traces with logs', async () => {
      const span = testTracer.startSpan('log-correlation');
      const context = span.spanContext();

      await logMessage('Processing request', {
        traceId: context.traceId,
        spanId: context.spanId,
      });

      const correlatedLogs = await queryLogs(context.traceId);
      expect(correlatedLogs).toHaveLength(1);
      expect(correlatedLogs[0].traceId).toBe(context.traceId);
    });

    it('correlates traces with metrics', async () => {
      const span = testTracer.startSpan('metric-correlation');
      span.end();

      const metrics = await queryMetrics({
        traceId: span.spanContext().traceId,
      });
      expect(metrics.durationHistogram).toBeDefined();
    });
  });

  describe('Region-Aware Latency & Failure Scenarios', () => {
    it('enforces latency budgets per region', async () => {
      const regions = ['us-east-1', 'eu-west-1', 'ap-southeast-1'];
      const budgets = { 'us-east-1': 200, 'eu-west-1': 300, 'ap-southeast-1': 400 };

      for (const region of regions) {
        const durations = [];
        for (let i = 0; i < 10; i++) {
          const duration = await measureRequest({ region });
          durations.push(duration);
        }
        const p99 = percentile(durations, 99);
        expect(p99).toBeLessThan(budgets[region]);
      }
    });

