      await simulateRegionFailure('us-east-1');

      const response = await callWithFailover({ preferRegion: 'us-east-1' });
      expect(response.region).not.toBe('us-east-1');
      expect(span.spanContext().traceId).toBeDefined();
    });

    it('validates SLO under failure injection', async () => {
      await injectFault('latency', { addedDelay: 5000 });

      const results = await runLoadTest({ duration: '5m', targetSLO: 0.99 });
      expect(results.availability).toBeGreaterThan(0.95);
    });
  });
});
