- Broker outages, gateway fallback, and eventual consistency
- Idempotency and replay protection

## Code Example
```javascript
// Pseudo-test harness sketch
const { createTenantContext, enqueueEvent, streamEvents } = require('./test-harness');

describe('Notification API E2E', () => {
  it('enforces per-tenant isolation', async () => {
    const [tenantA, tenantB] = await Promise.all([
      createTenantContext('tenant-a'),
      createTenantContext('tenant-b')
    ]);
    await enqueueEvent(tenantA, { type: 'order.placed', payload: { id: 'order-1' } });
    await enqueueEvent(tenantB, { type: 'order.placed', payload: { id: 'order-2' } });

    const eventsA = await streamEvents(tenantA, { timeout: 2000 });
    expect(eventsA.map(e => e.payload.id)).not.toContain('order-2');
  });

  it('guarantees in-order delivery within shards', async () => {
    const ctx = await createTenantContext('tenant-a');
    const sequence = ['a', 'b', 'c'];
    for (const id of sequence) {
      await enqueueEvent(ctx, { type: 'step', payload: { id }, shardKey: 'shard-1' });
    }
    const events = await streamEvents(ctx, { timeout: 2000 });
    expect(events.map(e => e.payload.id)).toEqual(sequence);
  });

  it('handles backpressure during reconnection', async () => {
    const ctx = await createTenantContext('tenant-a');
    const events = streamEvents(ctx, { bufferLimit: 10 });
    await enqueueBurst(ctx, 100);
    expect(await ctx.getDroppedEventCount()).toBe(0);
    expect(await ctx.getBackpressureMetric()).toBeGreaterThan(0);
    await events.disconnect();
    const reconnected = await streamEvents(ctx, { bufferLimit: 10 });
    expect(await reconnected.getResumptionOffset()).toBeGreaterThan(0);
  });

  it('falls back gracefully when broker is unavailable', async () => {
    const ctx = await createTenantContext('tenant-a');
    await ctx.simulateBrokerOutage();
    const result = await enqueueEvent(ctx, { type: 'alert' });
    expect(result.status).toBe('queued');
    expect(await ctx.getFallbackMetric()).toBe(1);
    await ctx.restoreBroker();
    const events = await streamEvents(ctx, { timeout: 5000 });
    expect(events.map(e => e.type)).toContain('alert');
  });
});
```

## Concrete Test Cases

| Test Case | Scope | Acceptance Criteria |
|-----------|-------|---------------------|
| Tenant Isolation | Cross-tenant | Tenant A never receives Tenant B events |
| Shard Ordering | Intra-shard | Events within same shard maintain FIFO order |
| Reconnection | Client | Client reconnects within 5s, resumes from last acknowledged offset |
| Backpressure | Server | Buffer full triggers 503, client retries with exponential backoff |
| Broker Fallback | Gateway | Enqueued events persist, delivery resumes within 30s of recovery |
| Message Deduplication | Idempotency | Duplicate event IDs do not result in duplicate delivery |

## Tooling Recommendations
- **k6** or **Artillery**: Load testing and throughput validation
- **MockWebSocket** or **Selenium**: WebSocket client simulation
- **Toxiproxy** or **Chaos Mesh**: Network partition and broker failure injection
- **Prometheus + Grafana**: Metrics collection (latency, throughput, drop rates)
- **Postman/Newman**: REST endpoint validation

