// k6 script for multi-tenant stream validation
import http from 'k6/http';
import { check } from 'k6';

export const options = {
  scenarios: {
    multi_tenant_streams: {
      executor: 'ramping-vus',
      vus: 50,
      duration: '5m',
    },
  },
};

const tenants = ['tenant-a', 'tenant-b', 'tenant-c'];

export default function () {
  const tenantId = tenants[Math.floor(Math.random() * tenants.length)];
  const res = http.get(`https://api.example.com/streams/${tenantId}`, {
    headers: { 'Tenant-Id': tenantId },
    tags: { name: 'stream_test' },
  });

  check(res, {
    'stream initialized': (r) => r.status === 200,
    'has event-stream content-type': (r) =>
      r.headers['Content-Type'].includes('text/event-stream'),
  });
}
```

## Recommended Tooling

